1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	export function claimOffice(request: any): any {
13	  const items = request.steps[0].items;
14	  let basePremium = 0;
15	  for (const item of items) {
16	    basePremium += BASE_PREMIUMS[item.type];
17	  }
18	  return [{ premium: basePremium + PROCESSING_FEE }];
19	}
